#include <stdio.h>

long long totalSubarrays(int arr[], int n, int limit) {
    long long ans = 0;
    int i = 0;
    while (i < n) {
        if (arr[i] > limit) { i++; continue; }
        long long cnt = 0;
        while (i < n && arr[i] <= limit) { cnt++; i++; }
        ans += cnt * (cnt + 1) / 2;
    }
    return ans;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        int arr[1005];
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        long long leK = totalSubarrays(arr, N, K);
        long long leKm1 = totalSubarrays(arr, N, K - 1);
        printf("%lld\n", leK - leKm1);
    }
    return 0;
}

