#include <bits/stdc++.h>
using namespace std;

long long totalSubarrays(const vector<int>& a, int limit) {
    long long ans = 0;
    int n = a.size();
    int i = 0;
    while (i < n) {
        if (a[i] > limit) { ++i; continue; }
        long long cnt = 0;
        while (i < n && a[i] <= limit) { ++cnt; ++i; }
        ans += cnt * (cnt + 1) / 2;
    }
    return ans;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int N, K; cin >> N >> K;
        vector<int> a(N);
        for (int &x : a) cin >> x;
        long long leK = totalSubarrays(a, K);
        long long leKm1 = totalSubarrays(a, K - 1);
        cout << leK - leKm1 << '\n';
    }
    return 0;
}

